' > prompts/registry.yaml && printf '{"version":"2.1.0","eval_pass_rate":0.85,"records":[]}' > prompts/eval-history/rsc-reviewer/2.1.0.json && bash "$CLAUDE_PLUGIN_ROOT/commands/prompt-promote.sh" rsc-reviewer 2.1.0 --override-regression --reason "intentional cost reduction" --emit-audit "$PWD/.claude-tdd-pro/audit.jsonl" && grep "override-regression" .claude-tdd-pro/audit.jsonl 1>&2 && echo ok 1>&2
